#!/bin/sh
set -e

FILE="/usr/share/nginx/html/index.html"
TMP="/tmp/index-sofia-live.html"

awk '
BEGIN { skip=0 }
/<section id="sofia"/ {
  print "    <section id=\"sofia\" class=\"px-4 py-16 sm:px-6 lg:py-24\"><div class=\"mx-auto grid max-w-7xl items-center gap-12 rounded-[2rem] border border-cyan-300/25 bg-gradient-to-br from-sky-400/20 via-[#07111f] to-cyan-300/20 p-6 shadow-[0_0_90px_rgba(56,189,248,.16)] sm:rounded-[3rem] lg:grid-cols-[.82fr_1.18fr] lg:p-14\"><div><p class=\"text-sm font-black uppercase tracking-[0.28em] text-cyan-300\">sof<span class=\"text-white\">IA</span> en vivo</p><h2 class=\"mt-5 text-4xl font-black sm:text-5xl\">Prueba cómo <span class=\"rounded-2xl bg-sky-400 px-3 py-1 text-slate-950 shadow-[0_0_35px_rgba(56,189,248,.45)]\">AgendaOS</span> responde, orienta y convierte consultas en reservas.</h2><p class=\"mt-6 text-lg leading-9 text-white/60\">Haz preguntas reales sobre AgendaOS, planes, reservas, automatización, dashboard, demos o cómo sofIA puede ayudar a tu negocio.</p><div class=\"mt-8 grid gap-3 sm:grid-cols-2\"><button data-prompt=\"¿Qué incluye AgendaOS AI?\" class=\"quick rounded-2xl border border-sky-300/20 bg-white/5 px-4 py-3 text-left text-sm font-bold text-white/75 transition hover:border-sky-300/50 hover:bg-white/10\">¿Qué incluye AgendaOS AI?</button><button data-prompt=\"¿Sirve para una barbería o clínica dental?\" class=\"quick rounded-2xl border border-sky-300/20 bg-white/5 px-4 py-3 text-left text-sm font-bold text-white/75 transition hover:border-sky-300/50 hover:bg-white/10\">¿Sirve para mi rubro?</button><button data-prompt=\"¿Cómo funciona la prueba gratis de 30 días?\" class=\"quick rounded-2xl border border-sky-300/20 bg-white/5 px-4 py-3 text-left text-sm font-bold text-white/75 transition hover:border-sky-300/50 hover:bg-white/10\">Prueba gratis 30 días</button><button data-prompt=\"¿Cómo se conectan WhatsApp, agenda y dashboard?\" class=\"quick rounded-2xl border border-sky-300/20 bg-white/5 px-4 py-3 text-left text-sm font-bold text-white/75 transition hover:border-sky-300/50 hover:bg-white/10\">Sistema conectado</button></div></div><div class=\"card-hover rounded-[2.5rem] border border-cyan-300/20 bg-[#061524]/85 p-5 shadow-2xl backdrop-blur-2xl\"><div class=\"mb-5 flex items-center justify-between gap-4 border-b border-white/10 pb-5\"><div class=\"flex items-center gap-4\"><img src=\"https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=300&auto=format&fit=crop\" alt=\"sofIA asistente inteligente de AgendaOS\" class=\"h-16 w-16 rounded-full border-2 border-sky-300 object-cover shadow-lg shadow-sky-500/30\"><div><p class=\"text-2xl font-black\">sof<span class=\"text-sky-300\">IA</span></p><p class=\"text-sm font-semibold text-cyan-300\">Online · Respondiendo sobre AgendaOS</p></div></div><div class=\"rounded-full border border-emerald-300/20 bg-emerald-300/10 px-4 py-2 text-xs font-black text-emerald-200\">En vivo</div></div><div id=\"chatMessages\" class=\"max-h-[430px] min-h-[430px] space-y-4 overflow-auto rounded-[2rem] border border-white/10 bg-black/15 p-4\"><div class=\"flex justify-start\"><div class=\"max-w-[86%] rounded-[2rem] bg-white/6 px-5 py-4 text-sm leading-7 text-white/82\">Hola, soy sofIA. Puedo explicarte cómo AgendaOS ayuda a recibir reservas online, automatizar WhatsApp, gestionar clientes y operar tu negocio desde un dashboard conectado.</div></div></div><form id=\"sofiaForm\" class=\"mt-4 flex gap-3\"><input id=\"sofiaInput\" maxlength=\"500\" autocomplete=\"off\" placeholder=\"Pregúntale a sofIA sobre AgendaOS...\" class=\"min-w-0 flex-1 rounded-full border border-sky-300/15 bg-white/5 px-5 py-4 text-sm font-semibold text-white outline-none transition placeholder:text-white/35 focus:border-sky-300/50 focus:bg-white/10\"><button id=\"sofiaSend\" class=\"rounded-full bg-sky-400 px-6 py-4 text-sm font-black text-slate-950 transition hover:bg-cyan-300 disabled:cursor-not-allowed disabled:opacity-50\">Enviar</button></form><p id=\"sofiaStatus\" class=\"mt-3 text-center text-xs font-semibold text-white/35\">sofIA en vivo · AgendaOS AI</p></div></div></section>"
  print "    <script>"
  print "    const SOFIA_ENDPOINT = \"/api/sofia-chat\";"
  print "    const sessionId = localStorage.getItem(\"agendaos_sofia_session\") || crypto.randomUUID();"
  print "    localStorage.setItem(\"agendaos_sofia_session\", sessionId);"
  print "    const form = document.getElementById(\"sofiaForm\"), input = document.getElementById(\"sofiaInput\"), button = document.getElementById(\"sofiaSend\"), messages = document.getElementById(\"chatMessages\"), status = document.getElementById(\"sofiaStatus\");"
  print "    function escapeHtml(text){return String(text).replace(/[&<>\\x27\\\"]/g,c=>({\"&\":\"&amp;\",\"<\":\"&lt;\",\">\":\"&gt;\",\"\\x27\":\"&#39;\",\"\\\"\":\"&quot;\"}[c]));}"
  print "    function addMessage(role,text){const u=role===\"user\";messages.insertAdjacentHTML(\"beforeend\",`<div class=\"flex ${u?\"justify-end\":\"justify-start\"}\"><div class=\"max-w-[86%] rounded-[2rem] px-5 py-4 text-sm leading-7 ${u?\"bg-sky-400 text-slate-950 font-bold\":\"bg-white/6 text-white/82\"}\">${escapeHtml(text)}</div></div>`);messages.scrollTop=messages.scrollHeight;}"
  print "    function showTyping(){messages.insertAdjacentHTML(\"beforeend\",`<div id=\"typing\" class=\"flex justify-start\"><div class=\"rounded-[2rem] bg-white/6 px-5 py-4\"><span style=\"width:7px;height:7px;border-radius:999px;background:#7dd3fc;display:inline-block\"></span> <span style=\"width:7px;height:7px;border-radius:999px;background:#7dd3fc;display:inline-block\"></span> <span style=\"width:7px;height:7px;border-radius:999px;background:#7dd3fc;display:inline-block\"></span></div></div>`);messages.scrollTop=messages.scrollHeight;}"
  print "    function hideTyping(){const el=document.getElementById(\"typing\");if(el)el.remove();}"
  print "    async function askSofia(text){addMessage(\"user\",text);input.value=\"\";button.disabled=true;status.textContent=\"sofIA está escribiendo...\";showTyping();try{const r=await fetch(SOFIA_ENDPOINT,{method:\"POST\",headers:{\"Content-Type\":\"application/json\",\"X-AgendaOS-Client\":\"agendaos-home\"},body:JSON.stringify({message:text,sessionId})});const d=await r.json();hideTyping();addMessage(\"assistant\",d.reply||\"Puedo ayudarte con planes, reservas, automatización y sofIA.\");status.textContent=\"Conectado de forma segura a sofIA.\";}catch(e){hideTyping();addMessage(\"assistant\",\"sofIA está conectándose. Puedes preguntarme sobre reservas, automatización, dashboard o AgendaOS AI.\");status.textContent=\"sofIA en vivo · AgendaOS AI\";}finally{button.disabled=false;input.focus();}}"
  print "    if(form){form.addEventListener(\"submit\",e=>{e.preventDefault();const t=input.value.trim();if(t)askSofia(t);});document.querySelectorAll(\".quick\").forEach(b=>b.addEventListener(\"click\",()=>askSofia(b.dataset.prompt)));}"
  print "    </script>"
  skip=1
  next
}
skip && /<section id="planes"/ { print; skip=0; next }
skip { next }
{ print }
' "$FILE" > "$TMP"

mv "$TMP" "$FILE"
nginx -s reload

echo "sofIA live chat montado en AgendaOS."
